const last = flow.get("lastWokwiMqttMs");
const now = Date.now();
let age = (typeof last === "number" && last > 0) ? (now - last) : null;
if (age != null && age < 0 && age > -120000) age = 0;
const LIVE_MS = 4000;
const DEAD_MS = 7000;
let prev = flow.get("pipelineStableLive");
if (typeof prev !== "boolean") prev = false;
let streak = Number(flow.get("pipelineDeadPollStreak"));
if (!Number.isFinite(streak)) streak = 0;
let next;
if (age === null) {
    next = prev;
} else if (age > 600000) {
    next = false;
    streak = 0;
} else if (age <= LIVE_MS) {
    next = true;
    streak = 0;
} else if (age > DEAD_MS) {
    if (!prev) {
        next = false;
        streak = 0;
    } else {
        streak += 1;
        next = (streak >= 2) ? false : true;
    }
} else {
    streak = 0;
    next = prev;
}
flow.set("pipelineDeadPollStreak", streak);
flow.set("pipelineStableLive", next);
msg.headers = { "Content-Type": "application/json" };
msg.payload = { isLive: next };
return msg;

