function scheduleMsFromMidnight(now, timeZone) {
    if (!timeZone) {
        return ((now.getHours() * 60 + now.getMinutes()) * 60 + now.getSeconds()) * 1000 +
            now.getMilliseconds();
    }
    const parts = new Intl.DateTimeFormat("en-GB", {
        timeZone: timeZone,
        hour: "2-digit",
        minute: "2-digit",
        second: "2-digit",
        hour12: false,
    }).formatToParts(now);
    const num = (type) => {
        const p = parts.find((x) => x.type === type);
        return p ? Number(p.value) : 0;
    };
    return ((num("hour") * 60 + num("minute")) * 60 + num("second")) * 1000;
}

