let d = msg.payload || {};
let now = Date.now();

if (typeof d.temperature !== "number" || isNaN(d.temperature) || d.temperature === -999) {
    return [{ payload: "ML waiting for valid temperature..." }, null];
}

let model = context.get("model") || {
    history: [],
    ema: null,
    forecasts: [],
    errors: [],
    lastAssistAt: 0,
    lastForecastAt: 0
};

// 1) Evaluate older forecasts whose due time has arrived
let dueForecasts = model.forecasts.filter(f => now >= f.due);
for (let f of dueForecasts) {
    model.errors.push(Math.abs(d.temperature - f.pred));
}
if (model.errors.length > 20) {
    model.errors = model.errors.slice(-20);
}
model.forecasts = model.forecasts.filter(f => now < f.due);

// 2) Update rolling history
model.history.push({
    t: now,
    temp: d.temperature,
    occupied: !!d.occupied,
    light: Number(d.light || 0),
    fan: Number(d.fan || 0)
});
if (model.history.length > 60) {
    model.history = model.history.slice(-60);
}

// 3) Exponential moving average
if (model.ema === null) model.ema = d.temperature;
model.ema = 0.35 * d.temperature + 0.65 * model.ema;

// 4) Trend model using last 12 points
let points = model.history.slice(-12);
let ready = points.length >= 6;
let trendPred = d.temperature;
let slopePerMin = 0;
let residualStd = 999;
let confidence = 0.25;

if (ready) {
    let t0 = points[0].t;
    let n = points.length;
    let sumx = 0, sumy = 0, sumxy = 0, sumxx = 0;

    for (let p of points) {
        let x = (p.t - t0) / 60000.0;   // minutes
        let y = p.temp;
        sumx += x;
        sumy += y;
        sumxy += x * y;
        sumxx += x * x;
    }

    let denom = n * sumxx - sumx * sumx;
    let slope = 0;
    let intercept = d.temperature;

    if (denom !== 0) {
        slope = (n * sumxy - sumx * sumy) / denom;
        intercept = (sumy - slope * sumx) / n;
    }

    slopePerMin = slope;

    let futureX = ((now + 120000) - t0) / 60000.0;   // 2 minutes ahead
    trendPred = intercept + slope * futureX;

    let rss = 0;
    for (let p of points) {
        let x = (p.t - t0) / 60000.0;
        let yhat = intercept + slope * x;
        rss += Math.pow(p.temp - yhat, 2);
    }
    residualStd = Math.sqrt(rss / Math.max(1, n - 2));

    let confN = Math.min(1, n / 12);
    let confFit = 1 / (1 + residualStd);
    confidence = Math.max(0, Math.min(1, 0.45 * confN + 0.55 * confFit));
}

// 5) Small feature adjustments
let occBoost = d.occupied ? 0.20 : -0.10;
let lightBoost = Number(d.light || 0) > 0 ? 0.10 : 0;
let fanEffect = Number(d.fan || 0) > 0 ? -0.20 : 0;

let predicted = 0.60 * trendPred + 0.40 * model.ema + occBoost + lightBoost + fanEffect;

// Clamp unrealistic jumps
predicted = Math.max(d.temperature - 1.5, Math.min(d.temperature + 3.0, predicted));
predicted = Number(predicted.toFixed(1));

let threshold = Number(d.tempThreshold || 28);
let stable = Math.abs(slopePerMin) < 0.08;
let anomaly = Number(d.fan || 0) > 0 && slopePerMin > 0.12;

let assist =
    ready &&
    !!d.occupied &&
    !d.forceOff &&
    confidence >= 0.55 &&
    predicted > (threshold + 0.3);

// Cooldown so it does not spam commands
let cooldownOk = (now - model.lastAssistAt) > 180000;
if (!cooldownOk) assist = false;
if (assist) model.lastAssistAt = now;

// Save one forecast every 15s for later accuracy checking
if (ready && (now - model.lastForecastAt > 15000)) {
    model.forecasts.push({ due: now + 120000, pred: predicted });
    if (model.forecasts.length > 20) {
        model.forecasts = model.forecasts.slice(-20);
    }
    model.lastForecastAt = now;
}

let mae = null;
if (model.errors.length) {
    let total = model.errors.reduce((a, b) => a + b, 0);
    mae = Number((total / model.errors.length).toFixed(2));
}

context.set("model", model);

let statusText = assist
    ? "Pre-cooling suggested"
    : (anomaly ? "Possible cooling inefficiency" : (stable ? "Stable" : "Monitoring"));

let mlSnapshot = {
