function buildFallback(s) {
    let line1 = "Classroom status: telemetry unavailable; awaiting live MQTT data.";
    if (s.temperature != null || s.occupied !== undefined) {
        const occ = s.occupied ? "occupied" : "unoccupied";
        const temp = s.temperature != null ? s.temperature.toFixed(1) + "°C" : "unknown temperature";
        line1 = "Classroom is " + occ + " at " + temp + "; light " + (s.light ? "ON" : "OFF") + ", fan " + (s.fan ? "ON" : "OFF") + ", mode " + String(s.mode || "auto").toUpperCase() + ".";
    }
    if (s.forceOff) {
        line1 = "Outside scheduled college hours: automation requires lights and fan to remain OFF.";
    }

    let line2 = "Comfort: readings are within expected band for the current threshold.";
    if (s.temperature != null && s.temperature > s.tempThreshold + 0.5) {
        line2 = "Comfort: temperature exceeds the " + s.tempThreshold + "°C threshold — increase cooling or airflow.";
    } else if (s.temperature != null && s.temperature < 18) {
        line2 = "Comfort: room is cool; verify heating setpoints if occupants complain.";
    }
    if (s.forceOff) {
