function stripQuotes(k) {
    let key = typeof k === "string" ? k.trim() : "";
    if (key.length >= 2 && ((key.charCodeAt(0) === 34 && key.charCodeAt(key.length - 1) === 34) || (key.charCodeAt(0) === 39 && key.charCodeAt(key.length - 1) === 39))) {
        key = key.slice(1, -1).trim();
